-- Online Web Presence (High-Impact) - Assess (variant 1)
UPDATE product_content SET
  description = 'We assess how your web presence performs today across journeys, content, conversion, and AI readiness, and return prioritised recommendations your leadership team can act on.',
  positioning = 'Review how online web presence performs today, identify the biggest gaps, and leave with prioritised next steps and a practical roadmap.',
  hero_summary = 'We assess how your web presence performs today across journeys, content, conversion, and AI readiness, and return prioritised recommendations your leadership team can act on.',
  overview_paragraphs = '["We assess how your web presence performs today across journeys, content, conversion, and AI readiness, and return prioritised recommendations your leadership team can act on.","Review how online web presence performs today, identify the biggest gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews how your web presence supports discovery, engagement, and conversion across priority customer journeys.","You receive practical findings and a prioritised roadmap your teams can use for design, investment, and delivery decisions."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Assess","duration":"1 Week","body":"We evaluate your current state, stakeholder goals, and improvement opportunities for this service scope.","whatHappens":"Discovery workshops, evidence review, and gap analysis","dqEffort":"high","yourEffort":"medium","active":true}]}'::jsonb,
  package_highlights = '["Fixed discovery scope","Executive-ready findings","No obligation to proceed"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations run web estates with inconsistent journeys, weak conversion paths, and no clear view of AI readiness. This assessment gives you evidence-led priorities your leadership team can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented journeys","description":"Customers hit dead ends between discovery, content, and conversion."},{"title":"Weak conversion signals","description":"Teams optimise pages without shared metrics or testable hypotheses."},{"title":"No AI readiness view","description":"Personalisation and assistant use cases are discussed without a practical baseline."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Journey-led priorities","description":"You know which paths to fix first across content, UX, and conversion."},{"title":"Clear improvement backlog","description":"Gaps are ranked for design, investment, and delivery decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations are structured for governance review and next-stage funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online web presence advisory service.'
WHERE variant_id = 1;

