  hero_summary = 'Improve government operations and citizen services through better service workflows, case management, coordination, governance and digital enablement.',
  overview_paragraphs = '["Improve government operations and citizen services through better service workflows, case management, coordination, governance and digital enablement.","Implement agreed government operations and citizen services changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
